<script setup>
import { reactive, ref, computed, watch } from "vue";
import { rsvp } from "@/config/wedding.js";
import { submitRsvp } from "@/services/rsvp.js";
import { saveAttendance } from "@/services/attendance.js";

const form = reactive({
    fullName: "",
    attendance: "",
    drinks: "",
    allergies: "",
    transferNeeded: "",
    transferType: "",
});

const errors = reactive({});
const status = ref("idle"); // idle | submitting | success | error

const showTransferType = computed(() => form.transferNeeded === "yes");
// Гость не придёт — остальные вопросы не имеют смысла, прячем их.
const isDeclined = computed(() => form.attendance === "no");

// Если пользователь сменил ответ на "не нужен трансфер" — сбросить тип и его ошибку.
watch(showTransferType, (visible) => {
    if (!visible) {
        form.transferType = "";
        delete errors.transferType;
    }
});

function validate() {
    const next = {};
    if (!form.fullName.trim()) next.fullName = "Укажите фамилию и имя";
    if (!form.attendance) next.attendance = "Выберите вариант";
    // Для тех, кто не придёт, остальные вопросы скрыты и необязательны.
    if (!isDeclined.value) {
        if (!form.drinks.trim()) next.drinks = "Заполните поле";
        if (!form.transferNeeded) next.transferNeeded = "Выберите вариант";
        if (form.transferNeeded === "yes" && !form.transferType) {
            next.transferType = "Выберите вариант";
        }
    }
    Object.keys(errors).forEach((k) => delete errors[k]);
    Object.assign(errors, next);
    return Object.keys(next).length === 0;
}

async function onSubmit() {
    if (!validate()) return;

    status.value = "submitting";
    try {
        const result = await submitRsvp({ ...form });
        status.value = result.ok ? "success" : "error";
        if (result.ok) {
            // Запоминаем ответ: проголосовавшим «буду» откроется мини-игра.
            saveAttendance(form.fullName.trim(), form.attendance);
        }
    } catch (err) {
        console.error("[RSVP] submit error:", err);
        status.value = "error";
    }
}

function resetForm() {
    Object.assign(form, {
        fullName: "",
        attendance: "",
        drinks: "",
        allergies: "",
        transferNeeded: "",
        transferType: "",
    });
    Object.keys(errors).forEach((k) => delete errors[k]);
    status.value = "idle";
}
</script>

<template>
    <section class="card rsvp">
        <h2 class="section-title">{{ rsvp.title }}</h2>

        <form v-if="status !== 'success'" class="rsvp__form" novalidate @submit.prevent="onSubmit">
            <!-- Q1 ФИ -->
            <div class="rsvp__field">
                <label class="rsvp__label" for="rsvp-fullname">
                    {{ rsvp.questions.fullName.label }}
                </label>
                <input
                    id="rsvp-fullname"
                    v-model="form.fullName"
                    type="text"
                    class="rsvp__input"
                    :class="{ 'rsvp__input--error': errors.fullName }"
                    :placeholder="rsvp.questions.fullName.placeholder"
                    autocomplete="name"
                >
                <div v-if="errors.fullName" class="rsvp__error">{{ errors.fullName }}</div>
            </div>

            <!-- Q2 Сможете присутствовать -->
            <fieldset class="rsvp__field rsvp__field--group">
                <legend class="rsvp__label">{{ rsvp.questions.attendance.label }}</legend>
                <label
                    v-for="opt in rsvp.questions.attendance.options"
                    :key="opt.value"
                    class="rsvp__radio"
                >
                    <input
                        v-model="form.attendance"
                        type="radio"
                        name="attendance"
                        :value="opt.value"
                    >
                    <span class="rsvp__radio-mark" aria-hidden="true"></span>
                    <span>{{ opt.label }}</span>
                </label>
                <div v-if="errors.attendance" class="rsvp__error">{{ errors.attendance }}</div>
            </fieldset>

            <!-- Гость не придёт: вместо остальных вопросов — грустный котик -->
            <div v-if="isDeclined" class="rsvp__declined">
                <img
                    :src="rsvp.declinedImage"
                    :alt="rsvp.declinedImageAlt || ''"
                    class="rsvp__declined-image"
                    loading="lazy"
                >
                <p class="rsvp__declined-text">Очень жаль! Нам будет вас не хватать.</p>
            </div>

            <template v-if="!isDeclined">
            <!-- Q3 Алкоголь -->
            <div class="rsvp__field">
                <label class="rsvp__label" for="rsvp-drinks">
                    {{ rsvp.questions.drinks.label }}
                </label>
                <textarea
                    id="rsvp-drinks"
                    v-model="form.drinks"
                    class="rsvp__input rsvp__textarea"
                    :class="{ 'rsvp__input--error': errors.drinks }"
                    :placeholder="rsvp.questions.drinks.placeholder"
                    rows="3"
                ></textarea>
                <div v-if="errors.drinks" class="rsvp__error">{{ errors.drinks }}</div>
            </div>

            <!-- Q4 Аллергия (необязательный) -->
            <div class="rsvp__field">
                <label class="rsvp__label" for="rsvp-allergies">
                    {{ rsvp.questions.allergies.label }}
                </label>
                <textarea
                    id="rsvp-allergies"
                    v-model="form.allergies"
                    class="rsvp__input rsvp__textarea"
                    :placeholder="rsvp.questions.allergies.placeholder"
                    rows="2"
                ></textarea>
            </div>

            <!-- Q5 Нужен трансфер -->
            <fieldset class="rsvp__field rsvp__field--group">
                <legend class="rsvp__label">{{ rsvp.questions.transferNeeded.label }}</legend>
                <label
                    v-for="opt in rsvp.questions.transferNeeded.options"
                    :key="opt.value"
                    class="rsvp__radio"
                >
                    <input
                        v-model="form.transferNeeded"
                        type="radio"
                        name="transferNeeded"
                        :value="opt.value"
                    >
                    <span class="rsvp__radio-mark" aria-hidden="true"></span>
                    <span>{{ opt.label }}</span>
                </label>
                <div v-if="errors.transferNeeded" class="rsvp__error">{{ errors.transferNeeded }}</div>
            </fieldset>

            <!-- Q6 Тип трансфера (условный) -->
            <fieldset v-if="showTransferType" class="rsvp__field rsvp__field--group">
                <legend class="rsvp__label">{{ rsvp.questions.transferType.label }}</legend>
                <label
                    v-for="opt in rsvp.questions.transferType.options"
                    :key="opt.value"
                    class="rsvp__radio"
                >
                    <input
                        v-model="form.transferType"
                        type="radio"
                        name="transferType"
                        :value="opt.value"
                    >
                    <span class="rsvp__radio-mark" aria-hidden="true"></span>
                    <span>{{ opt.label }}</span>
                </label>
                <div v-if="errors.transferType" class="rsvp__error">{{ errors.transferType }}</div>
            </fieldset>
            </template>

            <button
                type="submit"
                class="rsvp__submit"
                :disabled="status === 'submitting'"
            >
                {{ status === "submitting" ? "Отправляем…" : "Отправить" }}
            </button>

            <div v-if="status === 'error'" class="rsvp__notice rsvp__notice--error">
                Не удалось отправить. Попробуйте ещё раз.
            </div>
        </form>

        <div v-else class="rsvp__success">
            <div class="rsvp__success-icon" aria-hidden="true">✓</div>
            <h3 class="rsvp__success-title">Спасибо!</h3>
            <p v-if="isDeclined" class="rsvp__success-text">
                Ваш ответ записан. Жаль, что не&nbsp;увидимся&nbsp;— спасибо, что предупредили!
            </p>
            <p v-else class="rsvp__success-text">
                Ваш ответ записан. Будем рады видеть вас на&nbsp;нашем празднике.
            </p>
            <button type="button" class="rsvp__link" @click="resetForm">
                Заполнить ещё раз
            </button>
        </div>
    </section>
</template>

