// Слой отправки RSVP. Сейчас работает как заглушка: пишет в localStorage + console.
// Когда подключим Google Sheets:
//   1. Создаём Google Sheet → Apps Script → doPost(e) пишет JSON.parse(e.postData.contents)
//      в очередную строку таблицы.
//   2. Deploy → New deployment → Web app → Execute as: Me, Access: Anyone → копируем URL.
//   3. В .env.local задаём VUE_APP_RSVP_ENDPOINT=<этот URL> и перезапускаем dev-сервер.
// Сам этот файл при подключении менять не нужно.

const STORAGE_KEY = "wedding-rsvp-responses";

function getEndpoint() {
    return (process.env.VUE_APP_RSVP_ENDPOINT || "").trim();
}

function readLocal() {
    try {
        return JSON.parse(localStorage.getItem(STORAGE_KEY) || "[]");
    } catch {
        return [];
    }
}

function writeLocal(entry) {
    const all = readLocal();
    all.push(entry);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(all));
    return all;
}

async function submitRemote(endpoint, payload) {
    // Apps Script Web App не отдаёт CORS-заголовки для произвольных origin'ов —
    // поэтому используем no-cors с text/plain. Ответ читать нельзя, но запись пройдёт.
    await fetch(endpoint, {
        method: "POST",
        mode: "no-cors",
        headers: { "Content-Type": "text/plain;charset=utf-8" },
        body: JSON.stringify(payload),
    });
}

export async function submitRsvp(answers) {
    const payload = {
        ...answers,
        submittedAt: new Date().toISOString(),
    };

    const endpoint = getEndpoint();
    if (endpoint) {
        try {
            await submitRemote(endpoint, payload);
            return { ok: true, mode: "remote" };
        } catch (err) {
            console.error("[RSVP] remote submit failed, falling back to local:", err);
            writeLocal({ ...payload, _failedRemote: true });
            return { ok: false, mode: "local-fallback", error: err };
        }
    }

    const all = writeLocal(payload);
    console.log("[RSVP] saved locally (stub mode):", payload);
    console.log("[RSVP] all stored responses:", all);
    return { ok: true, mode: "local-stub" };
}

export function getStoredResponses() {
    return readLocal();
}

// Отправка рекорда мини-игры в ту же табличку (скрипт различает по type).
export async function submitGameScore(fullName, score) {
    const payload = {
        type: "score",
        fullName,
        score,
        submittedAt: new Date().toISOString(),
    };

    const endpoint = getEndpoint();
    if (!endpoint) {
        console.log("[GAME] score saved locally (stub mode):", payload);
        return { ok: true, mode: "local-stub" };
    }

    try {
        await submitRemote(endpoint, payload);
        return { ok: true, mode: "remote" };
    } catch (err) {
        console.error("[GAME] score submit failed:", err);
        return { ok: false, error: err };
    }
}
