<script setup>
import { computed, nextTick, onMounted, onBeforeUnmount, watch } from "vue";
import HeroSection from "@/components/HeroSection.vue";
import ProgramSection from "@/components/ProgramSection.vue";
import LocationSection from "@/components/LocationSection.vue";
import DressCodeSection from "@/components/DressCodeSection.vue";
import OrganizationSection from "@/components/OrganizationSection.vue";
import RsvpSection from "@/components/RsvpSection.vue";
import GameSection from "@/components/GameSection.vue";
import { attendanceState } from "@/services/attendance.js";

// Мини-игра открывается только тем, кто проголосовал «обязательно буду».
const showGame = computed(() => attendanceState.answer?.attendance === "yes");

// Карточка игры может появиться уже после монтирования (сразу после
// голосования) — навешиваем на неё reveal-анимацию вдогонку.
watch(showGame, async (visible) => {
    if (!visible || !observer) return;
    await nextTick();
    document.querySelectorAll(".invitation > .card:not(.reveal)").forEach((el) => {
        el.classList.add("reveal");
        observer.observe(el);
    });
});

let observer;

onMounted(() => {
    if (!("IntersectionObserver" in window)) return;

    const cards = document.querySelectorAll(".invitation > .card");
    observer = new IntersectionObserver(
        (entries) => {
            entries.forEach((entry) => {

                entry.target.classList.toggle("reveal--visible", entry.isIntersecting);
            });
        },
        { threshold: 0, rootMargin: "0px 0px -60px 0px" }
    );

    cards.forEach((el) => {
        el.classList.add("reveal");
        observer.observe(el);
    });
});

onBeforeUnmount(() => observer?.disconnect());
</script>

<template>
    <main class="invitation">
        <HeroSection />
        <ProgramSection />
        <LocationSection />
        <DressCodeSection />
        <OrganizationSection />
        <RsvpSection />
        <GameSection v-if="showGame" />
    </main>
</template>
