// Сохранённый ответ гостя на RSVP (localStorage) — нужен, чтобы после
// голосования «буду» показать блок с мини-игрой и подписывать рекорды именем.
import { reactive } from "vue";

const STORAGE_KEY = "wedding-rsvp-answer";

function load() {
    try {
        return JSON.parse(localStorage.getItem(STORAGE_KEY)) || null;
    } catch {
        return null;
    }
}

export const attendanceState = reactive({
    // { fullName, attendance } | null
    answer: load(),
});

export function saveAttendance(fullName, attendance) {
    attendanceState.answer = { fullName, attendance };
    try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(attendanceState.answer));
    } catch {
        // приватный режим — ну и ладно, блок просто пропадёт после перезагрузки
    }
}
