<script setup>
import { ref, onMounted, onBeforeUnmount } from "vue";
import { game } from "@/config/wedding.js";
import { attendanceState } from "@/services/attendance.js";
import { submitGameScore } from "@/services/rsvp.js";

const BEST_KEY = "wedding-game-best";

const canvasEl = ref(null);
const phase = ref("idle"); // idle | running | over
const score = ref(0);
const best = ref(Number(localStorage.getItem(BEST_KEY)) || 0);

// --- Параметры раннера ---
const GRAVITY = 2300;        // px/s²
const JUMP_VELOCITY = 840;   // px/s вверх (прыжок при удержании)
const JUMP_CUT = 0.4;        // отпустил рано — взлёт гасится до этой доли
const START_SPEED = 280;     // px/s
const MAX_SPEED = 700;
const ACCEL = 9;             // прирост скорости, px/s за секунду

const GROOM = "🤵";
const OBSTACLES = ["🎂", "💐", "🍾", "💍"];

let ctx = null;
let raf = 0;
let lastTs = 0;
let W = 0;
let H = 0;

let groomY = 0;   // высота над землёй
let groomVy = 0;
let speed = START_SPEED;
let distance = 0;
let spawnIn = 0;
let items = [];   // { x, emoji, size }

const groundY = () => H - 30;
const groomX = () => Math.max(44, W * 0.14);

function setupCanvas() {
    const canvas = canvasEl.value;
    if (!canvas) return;
    const dpr = window.devicePixelRatio || 1;
    W = canvas.clientWidth;
    H = canvas.clientHeight;
    canvas.width = W * dpr;
    canvas.height = H * dpr;
    ctx = canvas.getContext("2d");
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.textAlign = "center";
    draw();
}

function reset() {
    groomY = 0;
    groomVy = 0;
    speed = START_SPEED;
    distance = 0;
    spawnIn = 1.2;
    items = [];
    score.value = 0;
}

function start() {
    if (phase.value === "running") return;
    reset();
    phase.value = "running";
    lastTs = 0;
    cancelAnimationFrame(raf);
    raf = requestAnimationFrame(tick);
}

function jump() {
    if (phase.value !== "running") return;
    if (groomY === 0) groomVy = JUMP_VELOCITY;
}

// Высота прыжка зависит от длительности нажатия: отпустили, пока жених
// ещё летит вверх — остаток взлёта обрезается, получается короткий прыжок.
function endJump() {
    if (groomVy > 0) groomVy *= JUMP_CUT;
}

function onKeyDown(e) {
    if (e.code !== "Space" || e.repeat) return;
    e.preventDefault();
    if (phase.value === "running") jump();
    else start();
}

function onKeyUp(e) {
    if (e.code !== "Space") return;
    endJump();
}

function tick(ts) {
    if (!lastTs) lastTs = ts;
    const dt = Math.min((ts - lastTs) / 1000, 0.05);
    lastTs = ts;

    // скорость и счёт
    speed = Math.min(MAX_SPEED, speed + ACCEL * dt);
    distance += speed * dt;
    score.value = Math.floor(distance / 10);

    // прыжок
    groomY += groomVy * dt;
    groomVy -= GRAVITY * dt;
    if (groomY <= 0) {
        groomY = 0;
        groomVy = 0;
    }

    // спавн препятствий: интервал в секундах из «дистанции» в px,
    // нижняя граница оставляет время приземлиться между прыжками
    spawnIn -= dt;
    if (spawnIn <= 0) {
        const clusterWidth = spawnCluster();
        spawnIn = (420 + Math.random() * 620) / speed + 0.45 + clusterWidth / speed;
    }
    items.forEach((it) => (it.x -= speed * dt));
    items = items.filter((it) => it.x > -60);

    // столкновения (хитбоксы заметно меньше эмодзи — щадящие)
    const gx = groomX();
    const gTop = groundY() - groomY - 40;
    const gBox = { left: gx - 12, right: gx + 12, top: gTop, bottom: gTop + 40 };
    for (const it of items) {
        const half = it.size * 0.3;
        const oTop = groundY() - it.size * 0.7;
        if (
            gBox.right > it.x - half &&
            gBox.left < it.x + half &&
            gBox.bottom > oTop
        ) {
            gameOver();
            break;
        }
    }

    draw();
    if (phase.value === "running") raf = requestAnimationFrame(tick);
}

// С ростом скорости препятствия идут группами: «стенка» из слитных
// элементов требует высокого прыжка с удержанием, цепочка с короткими
// промежутками — серии быстрых прыжков.
function spawnCluster() {
    const difficulty = (speed - START_SPEED) / (MAX_SPEED - START_SPEED); // 0..1
    const count = pickCount(difficulty);
    const randomItem = () => ({
        emoji: OBSTACLES[Math.floor(Math.random() * OBSTACLES.length)],
        size: 32 + Math.random() * 10,
    });

    const startX = W + 50;
    if (count === 1) {
        items.push({ x: startX, ...randomItem() });
        return 0;
    }

    if (Math.random() < 0.5) {
        // слитная «стенка» — перепрыгивается одним длинным прыжком
        let offset = 0;
        for (let i = 0; i < count; i++) {
            const item = randomItem();
            items.push({ x: startX + offset, ...item });
            offset += item.size * 0.75;
        }
        return offset;
    }

    // цепочка — на каждый элемент свой прыжок, времени впритык
    const gap = speed * 0.78;
    for (let i = 0; i < count; i++) {
        items.push({ x: startX + i * gap, ...randomItem() });
    }
    return (count - 1) * gap;
}

// Шанс пар и троек растёт со сложностью: до ~15% скорости только
// одиночные, тройки подключаются после ~45%.
function pickCount(difficulty) {
    const pairChance = Math.max(0, difficulty - 0.15) * 0.7;
    const tripleChance = Math.max(0, difficulty - 0.45) * 0.5;
    const r = Math.random();
    if (r < tripleChance) return 3;
    if (r < tripleChance + pairChance) return 2;
    return 1;
}

function draw() {
    if (!ctx) return;
    ctx.clearRect(0, 0, W, H);

    ctx.strokeStyle = "rgba(42, 29, 24, 0.35)";
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(0, groundY() + 1.5);
    ctx.lineTo(W, groundY() + 1.5);
    ctx.stroke();

    ctx.font = "42px serif";
    ctx.fillText(GROOM, groomX(), groundY() - groomY);
    for (const it of items) {
        ctx.font = `${it.size}px serif`;
        ctx.fillText(it.emoji, it.x, groundY());
    }
}

function gameOver() {
    phase.value = "over";
    cancelAnimationFrame(raf);
    if (score.value > best.value) {
        best.value = score.value;
        try {
            localStorage.setItem(BEST_KEY, String(best.value));
        } catch { /* приватный режим */ }
        // В зачёт уходят только улучшения личного рекорда — без спама в табличку.
        const name = attendanceState.answer?.fullName || "Гость";
        submitGameScore(name, best.value);
    }
}

onMounted(() => {
    setupCanvas();
    window.addEventListener("resize", setupCanvas);
    window.addEventListener("keydown", onKeyDown);
    window.addEventListener("keyup", onKeyUp);
});

onBeforeUnmount(() => {
    cancelAnimationFrame(raf);
    window.removeEventListener("resize", setupCanvas);
    window.removeEventListener("keydown", onKeyDown);
    window.removeEventListener("keyup", onKeyUp);
});
</script>

<template>
    <section class="card card--soft game">
        <h2 class="section-title">{{ game.title }}</h2>
        <p class="game__intro">{{ game.intro }}</p>

        <div class="game__arena">
            <div class="game__hud">
                <span>Очки: {{ score }}</span>
                <span>Рекорд: {{ best }}</span>
            </div>

            <canvas
                ref="canvasEl"
                class="game__canvas"
                @pointerdown.prevent="jump"
                @pointerup.prevent="endJump"
                @pointerleave="endJump"
                @pointercancel="endJump"
            ></canvas>

            <div
                v-if="phase !== 'running'"
                class="game__overlay"
                @pointerdown.prevent="start"
            >
                <template v-if="phase === 'over'">
                    <div class="game__overlay-score">{{ score }} очков</div>
                    <div class="game__overlay-hint">Тапни, чтобы сыграть ещё раз</div>
                </template>
                <template v-else>
                    <div class="game__overlay-hint">Тапни, чтобы начать</div>
                </template>
            </div>
        </div>

        <p class="game__rules">{{ game.rules }}</p>
    </section>
</template>

